#!/usr/bin/perl
use strict;
use warnings;
use DBI;

my $dbh = DBI->connect("DBI:mysql:database=your_database;host=localhost", "your_username", "your_password") || die "Cannot connect to the database: $DBI::errstr";

my $username = param('username');
my $password = param('password');

if (!$username || !$password) {
    print header, start_html("Login Error", undef, {-title=>"Login Error"});
    print "Error: Please enter both username and password.<br>";
    print end_html;
    exit;
}

my $sth = $dbh->prepare("SELECT * FROM users WHERE username='$username' AND password='$password'");
$sth->execute();

if (!$sth->rows) {
    print header, start_html("Login Error", undef, {-title=>"Login Error"});
    print "Error: Invalid username or password.<br>";
    print end_html;
} else {
    # Redirect to a success page after successful login
    print header('Location: /success.html'), endl;
}

$sth->finish();
$dbh->disconnect();